// toggle btn category
const displayBtn = () => {
  const Catagories = document.querySelector(".Catagories");
  const toggleCategories = document.querySelector(".toggle-categories");
  const ultoggleCategories = document.querySelector(".ul-toggleCategories");

  Catagories.addEventListener("click", () => {
    toggleCategories.classList.toggle("active");
  });

  const category = products.map((item) => item.category);
  const buttons = ["All", ...new Set(category)];

  ultoggleCategories.innerHTML = buttons
    .map((btn) => {
      return `
        <li class="btn-cat" data-id="${btn}">
          <a href="#">${btn}</a>
        </li>
      `;
    })
    .join("");

  const allBtn = document.querySelectorAll(".btn-cat");

  allBtn.forEach((button) => {
    button.addEventListener("click", function (e) {
      e.preventDefault();

      const id = this.dataset.id;
      const filter = products.filter(
        (item) => item.category === id
      );

      if(id === "All"){
        displayCat(products);
      }else{

        displayCat(filter);
      }

      // Optional: close menu after selection
      // toggleCategories.classList.remove("active");
    });
  });

  // displayCat(products);
};

